import org.springframework.security.oauth2.server.authorization.OAuth2AuthorizationCode;
import org.springframework.security.oauth2.server.authorization.OAuth2AuthorizationCodeService;
import org.springframework.util.Assert;

import java.time.Instant;
import java.util.Map;
import java.util.concurrent.ConcurrentHashMap;

/**
 * An in-memory implementation of {@link OAuth2AuthorizationCodeService} that stores
 * authorization codes in a {@code HashMap} and supports a 10-minute expiration.
 * <p>
 * NOTE: This implementation is for demonstration purposes only.
 * For production environments, a persistent and distributed store (e.g., database, Redis)
 * should be used.
 * </p>
 */
public class InMemoryAuthorizationCodeService implements OAuth2AuthorizationCodeService {

    private final Map<String, AuthorizationCodeData> authorizationCodes = new ConcurrentHashMap<>();
    private static final long AUTHORIZATION_CODE_EXPIRATION_SECONDS = 600; // 10 minutes

    @Override
    public void save(OAuth2AuthorizationCode authorizationCode) {
        Assert.notNull(authorizationCode, "authorizationCode cannot be null");
        authorizationCodes.put(authorizationCode.getTokenValue(), new AuthorizationCodeData(authorizationCode));
    }

    @Override
    public OAuth2AuthorizationCode remove(String tokenValue) {
        Assert.hasText(tokenValue, "tokenValue cannot be empty");
        AuthorizationCodeData data = authorizationCodes.remove(tokenValue);
        return (data != null) ? data.getCode() : null;
    }

    @Override
    public OAuth2AuthorizationCode consume(String tokenValue) {
        Assert.hasText(tokenValue, "tokenValue cannot be empty");
        AuthorizationCodeData data = authorizationCodes.remove(tokenValue);
        if (data == null) {
            return null;
        }

        if (data.isExpired()) {
            return null; // Code is expired
        }
        return data.getCode();
    }

    private static class AuthorizationCodeData {
        private final OAuth2AuthorizationCode code;
        private final Instant expiration;

        AuthorizationCodeData(OAuth2AuthorizationCode code) {
            this.code = code;
            this.expiration = Instant.now().plusSeconds(AUTHORIZATION_CODE_EXPIRATION_SECONDS);
        }

        public OAuth2AuthorizationCode getCode() {
            return code;
        }

        public boolean isExpired() {
            return Instant.now().isAfter(this.expiration);
        }
    }
}

